%cutes on button press in embedding.
function embedding_Callback(hObject, eventdata, handles)
% hObject    handle to embedding (see GCBO)
% eventdata  reserved - to be defined in a future version of MATLAB
% handles    structure with handles and user data (see GUIDATA)
 global Bin;
global added;
global embeddedImg;
global pseudoRandom;
if isfield(handles, 'image')%get image from guiddata
     HospitalLogo=handles.image;
     
    if (added==1)
        if isfield(handles, 'image2')%get image from guiddata
     img=handles.image2;
          
             
[rows,cols]=size(img);

Binary=zeros(rows,cols);
Binary=string(Binary);
nImg=img;
% md5hash function to make string for watermark
for i=1:1:rows
    for j=1:1:cols
        Binary(i,j)=dec2bin(img(i,j),8);
        k=char(Binary(i,j));
        k(1,8)='0';
        Binary(i,j)=k;
        nImg(i,j)=bin2dec(Binary(i,j));
    end
end

x=DataHash(nImg);
HashBinary=zeros(1,32);
HashBinary=string(HashBinary);

for i=1:1:32
   HashBinary(1,i)=dec2bin(x(1,i),8); 
end
% concatinating watermarks in w
VectorW=zeros(1,12544);
counter=1;
% adding logo
for i=1:1:64
    for j=1:1:64
        if HospitalLogo(i,j)==0
            VectorW(1,counter)=0;
        else        
            VectorW(1,counter)=1;
        end
        counter=counter+1;
    end
end
% adding info
for i=1:1:1024
    k=char(Bin(1,i));
    for j=1:1:8
        if k(1,j)=='0'
            VectorW(1,counter)=0;
        else
            VectorW(1,counter)=1;
        end
        counter=counter+1;
    end
end
% adding hash string
for i=1:1:32
    k=char(HashBinary(1,i));
    for j=1:1:8
        if k(1,j)=='0'
            VectorW(1,counter)=0;
        else
            VectorW(1,counter)=1;
        end
        counter=counter+1;
    end
end
