% segmentation
[T,EM]=graythresh(img);
imgcpy1=img;
imgcpy1 = padarray(imgcpy1,[1 1],0,'both');

Thresh=uint8(T*255);

[row,col]=size(img);

for i=1:1:row
    for j=1:1:col
        if imgcpy1(i,j)<Thresh
            imgcpy1(i,j)=255;
        end
            
    end
end
axes( handles.axes3);
imshow(imgcpy1)
imgcpy1=im2double(imgcpy1);
J=regiongrowing(imgcpy1,1,1);
nImg=imgcpy1-J;
counter=0;
for i=1:1:row
    for j=1:1:col
        if nImg(i,j)<0
            nImg(i,j)=255;
            counter=counter+1;
        end
    end
end


% Embedding in Image
embeddedImg=img;
embeddedImg=string(embeddedImg);
counter=1;
flag=0;
for i=1:1:row
    for j=1:1:col
        if counter<=12544
            if nImg(i,j)==255
                k=char(dec2bin(img(i,j),8));
                if W_star(1,counter)==1
                    k(1,8)='1';
                else
                    k(1,8)='0';
                end
                embeddedImg(i,j)=bin2dec(k);
                counter=counter+1;
            end
            
        else
            flag=1;
            break;
        end
    end
    if flag==1
        break;
    end
end

embeddedImg=uint8(str2double(embeddedImg));
 f = msgbox('Image embedded', 'Result','result')
