% --- Executes on button press in logo_load.
function logo_load_Callback(hObject, eventdata, handles)
% hObject    handle to logo_load (see GCBO)
% eventdata  reserved - to be defined in a future version of MATLAB
% handles    structure with handles and user data (see GUIDATA)


[filename, path]=uigetfile();
fullfilename=strcat(path,filename);
HospitalLogo=imread(fullfilename);

 
HospitalLogo=rgb2gray(HospitalLogo);
HospitalLogo=imresize(HospitalLogo,[64 64]);
image=imbinarize(HospitalLogo);
axes( handles.axes2);
imshow(image );
%  title('HospitalLogo ')
handles.image = image;%handle is used further to get image
guidata(hObject, handles);%save in guide so we can use in otherpush button
% --- Executes on button press in patiengt_detail.
function patiengt_detail_Callback(hObject, eventdata, handles)
% hObject    handle to patiengt_detail (see GCBO)
% eventdata  reserved - to be defined in a future version of MATLAB
% handles    structure with handles and user data (see GUIDATA)

global Bin;
global added;

fileID = fopen('PatientRecord.txt','r');
formatSpec = '%c';

A = fscanf(fileID,formatSpec);

[Trow,Tcol]=size(A);

ASCII=zeros(Trow,1024);
Bin=zeros(Trow,1024);
Bin=string(Bin);

for i=1:1:Tcol
    ASCII(1,i)=double(char(A(1,i)));
end
for i=1:1:Tcol
    Bin(1,i)=dec2bin(ASCII(1,i),8);
end
for i=Tcol:1:1024
    Bin(1,i)=dec2bin(double(Bin(1,i)),8);
end
added=1;

